    if filters and len(filters) > MAX_FILTERS:
        raise ValueError(f"Too many filters. Maximum allowed: {MAX_FILTERS}")

    params = []
    where_clauses = []

    # Build SELECT clause with all columns for the table
    select_columns = [sql.Identifier(col) for col in table_config['columns']]

    # If full-text search is requested, add relevance score
    if search_text and table_config.get('text_search_columns'):
        ts_columns = table_config['text_search_columns']
        # Build tsvector from text search columns
        coalesce_parts = []
        for col in ts_columns:
            coalesce_parts.append(
                sql.SQL("coalesce({}, '')").format(sql.Identifier(col))
            )
        tsvector_expr = sql.SQL(" || ' ' || ").join(coalesce_parts)

        ts_query_placeholder = sql.Placeholder()
        params.append(search_text)

        relevance_expr = sql.SQL(
            "ts_rank(to_tsvector('english', {tsvector}), plainto_tsquery('english', {query}))"
        ).format(
            tsvector=tsvector_expr,
            query=ts_query_placeholder
        )

        select_columns.append(sql.SQL("{} AS relevance_score").format(relevance_expr))

        # Add WHERE clause for full-text search
        fts_where = sql.SQL(
            "to_tsvector('english', {tsvector}) @@ plainto_tsquery('english', {query})"
        ).format(
            tsvector=tsvector_expr,
            query=sql.Placeholder()
        )
        params.append(search_text)
        where_clauses.append(fts_where)

    # Build filter WHERE clauses
    if filters:
        for f in filters:
            field_name = f.get('field') if isinstance(f, dict) else f.field
            operator = f.get('operator') if isinstance(f, dict) else f.operator
            value = f.get('value') if isinstance(f, dict) else f.value
            values = f.get('values') if isinstance(f, dict) else f.values

            # Validate field and operator
            validate_column(table_name, field_name, 'filterable')
            validate_operator(operator)

            col_ident = sql.Identifier(field_name)

            if operator == 'eq':
                where_clauses.append(sql.SQL("{} = {}").format(col_ident, sql.Placeholder()))
                params.append(value)
            elif operator == 'neq':
                where_clauses.append(sql.SQL("{} != {}").format(col_ident, sql.Placeholder()))
                params.append(value)
            elif operator == 'gt':
                where_clauses.append(sql.SQL("{} > {}").format(col_ident, sql.Placeholder()))
                params.append(value)
            elif operator == 'gte':
                where_clauses.append(sql.SQL("{} >= {}").format(col_ident, sql.Placeholder()))
                params.append(value)
            elif operator == 'lt':
                where_clauses.append(sql.SQL("{} < {}").format(col_ident, sql.Placeholder()))
                params.append(value)
            elif operator == 'lte':
                where_clauses.append(sql.SQL("{} <= {}").format(col_ident, sql.Placeholder()))
                params.append(value)
            elif operator == 'like':
                where_clauses.append(sql.SQL("{} LIKE {}").format(col_ident, sql.Placeholder()))
                params.append(value)
            elif operator == 'ilike':
                where_clauses.append(sql.SQL("{} ILIKE {}").format(col_ident, sql.Placeholder()))
                params.append(value)
            elif operator == 'in':
                if not values:
                    raise ValueError("'in' operator requires 'values' list")
                placeholders = sql.SQL(', ').join([sql.Placeholder()] * len(values))
                where_clauses.append(
                    sql.SQL("{} IN ({})").format(col_ident, placeholders)
                )
                params.extend(values)
            elif operator == 'is_null':
                if value and value.lower() == 'true':
                    where_clauses.append(sql.SQL("{} IS NULL").format(col_ident))
                else:
                    where_clauses.append(sql.SQL("{} IS NOT NULL").format(col_ident))

    # Build the full query
    query_parts = [
        sql.SQL("SELECT {}").format(sql.SQL(', ').join(select_columns)),
        sql.SQL("FROM {}").format(sql.Identifier(table_name)),
    ]

    if where_clauses:
        query_parts.append(sql.SQL("WHERE {}").format(sql.SQL(" AND ").join(where_clauses)))

